import math
class Solution:
    def minSpeedOnTime(self, dist, hour):
        n = len(dist)
        # hour with two decimals -> hundredths
        h100 = int(round(hour * 100))
        if (n - 1) * 100 >= h100:
            return -1
        def ok(speed):
            # time in hundredths of an hour, exact via integer math on the last ride
            t100 = 0
            for i in range(n - 1):
                t100 += math.ceil(dist[i] / speed) * 100
            # last ride: dist[-1]/speed hours -> *100, compare exactly
            # t100 + dist[-1]*100/speed <= h100
            return t100 * speed + dist[-1] * 100 <= h100 * speed
        lo, hi = 1, 10000000
        while lo < hi:
            mid = (lo + hi) // 2
            if ok(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo if ok(lo) else -1

