import math
class Solution:
    def minSpeedOnTime(self, dist, hour):
        n = len(dist)
        h100 = int(round(hour * 100))
        if (n - 1) * 100 >= h100:
            return -1
        def feasible(speed):
            whole = 0
            for i in range(n - 1):
                whole += (dist[i] + speed - 1) // speed
            # whole + dist[-1]/speed <= hour  <=>  whole*speed*100 + dist[-1]*100 <= h100*speed
            return whole * speed * 100 + dist[-1] * 100 <= h100 * speed
        lo, hi = 1, 10000000
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

