var minSpeedOnTime = function(dist, hour) {
    const n = dist.length;
    const h100 = Math.round(hour * 100);
    if ((n - 1) * 100 >= h100) return -1;
    const feasible = (speed) => {
        let whole = 0;
        for (let i = 0; i < n - 1; i++) whole += Math.ceil(dist[i] / speed);
        return whole * speed * 100 + dist[n - 1] * 100 <= h100 * speed;
    };
    let lo = 1, hi = 10000000;
    while (lo < hi) {
        const mid = Math.floor((lo + hi) / 2);
        if (feasible(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
